   205→			}
   206→		}
   207→	} else {
   208→		while ((rc == 0 || contoper) && fgets(buf, sizeof(buf), fp) != NULL) {
   209→			buf[ strlen( buf ) - 1 ] = '\0'; /* remove trailing newline */
   210→
   211→			if ( *buf != '\0' ) {
   212→				rc = dodelete( ld, buf );
   213→				if ( rc != 0 )
   214→					retval = rc;
   215→			}
   216→		}
