   225→static int dodelete(
   226→    LDAP	*ld,
   227→    const char	*dn)
   228→{
   229→	int id;
   230→	int	rc, code;
   231→	char *matcheddn = NULL, *text = NULL, **refs = NULL;
   232→	LDAPControl **ctrls = NULL;
   233→	LDAPMessage *res;
   234→	int subentries = 0;
   235→
   236→	if ( verbose ) {
   237→		printf( _("%sdeleting entry \"%s\"\n"),
   238→			(dont ? "!" : ""), dn );
   239→	}
   240→
   241→	if ( dont ) {
   242→		return LDAP_SUCCESS;
   243→	}
   244→
   245→	/* If prune is on, remove a whole subtree.  Delete the children of the
   246→	 * DN recursively, then the DN requested.
   247→	 */
   248→	if ( prune ) {
   249→retry:;
   250→		deletechildren( ld, dn, subentries );
   251→	}
   252→
   253→	rc = ldap_delete_ext( ld, dn, NULL, NULL, &id );
   254→	if ( rc != LDAP_SUCCESS ) {
   255→		fprintf( stderr, "%s: ldap_delete_ext: %s (%d)\n",
   256→			prog, ldap_err2string( rc ), rc );
   257→		return rc;
   258→	}
   259→
   260→	for ( ; ; ) {
   261→		struct timeval tv;
   262→
   263→		if ( tool_check_abandon( ld, id ) ) {
   264→			return LDAP_CANCELLED;
   265→		}
   266→
   267→		tv.tv_sec = 0;
   268→		tv.tv_usec = 100000;
   269→
   270→		rc = ldap_result( ld, LDAP_RES_ANY, LDAP_MSG_ALL, &tv, &res );
   271→		if ( rc < 0 ) {
   272→			tool_perror( "ldap_result", rc, NULL, NULL, NULL, NULL );
   273→			return rc;
   274→		}
   275→
   276→		if ( rc != 0 ) {
   277→			break;
   278→		}
   279→	}
   280→
   281→	rc = ldap_parse_result( ld, res, &code, &matcheddn, &text, &refs, &ctrls, 1 );
   282→	if( rc != LDAP_SUCCESS ) {
   283→		fprintf( stderr, "%s: ldap_parse_result: %s (%d)\n",
   284→			prog, ldap_err2string( rc ), rc );
   285→		return rc;
   286→	}
   287→
   288→	switch ( code ) {
   289→	case LDAP_SUCCESS:
   290→		break;
   291→
   292→	case LDAP_NOT_ALLOWED_ON_NONLEAF:
   293→		if ( prune && !subentries ) {
   294→			subentries = 1;
   295→			goto retry;
   296→		}
   297→		/* fallthru */
   298→
   299→	default:
   300→		break;
   301→	}
   302→
   303→	if( code != LDAP_SUCCESS ) {
   304→		tool_perror( "ldap_delete", code, NULL, matcheddn, text, refs );
   305→	} else if ( verbose && 
   306→		((matcheddn && *matcheddn) || (text && *text) || (refs && *refs) ))
   307→	{
   308→		printf( _("Delete Result: %s (%d)\n"),
   309→			ldap_err2string( code ), code );
   310→
   311→		if( text && *text ) {
   312→			printf( _("Additional info: %s\n"), text );
   313→		}
   314→
   315→		if( matcheddn && *matcheddn ) {
   316→			printf( _("Matched DN: %s\n"), matcheddn );
   317→		}
   318→
   319→		if( refs ) {
   320→			int i;
   321→			for( i=0; refs[i]; i++ ) {
   322→				printf(_("Referral: %s\n"), refs[i] );
   323→			}
   324→		}
   325→	}
   326→
   327→	if (ctrls) {
   328→		tool_print_ctrls( ld, ctrls );
   329→		ldap_controls_free( ctrls );
   330→	}
   331→
   332→	ber_memfree( text );
   333→	ber_memfree( matcheddn );
   334→	ber_memvfree( (void **) refs );
   335→
   336→	return code;
   337→}
   338→
   339→/*
   340→ * Delete all the children of an entry recursively until leaf nodes are reached.
   341→ */
   342→static int deletechildren(
   343→	LDAP *ld,
   344→	const char *base,
   345→	int subentries )
   346→{
   347→	LDAPMessage *res, *e;
   348→	int entries;
   349→	int rc = LDAP_SUCCESS, srch_rc;
   350→	static char *attrs[] = { LDAP_NO_ATTRS, NULL };
   351→	LDAPControl c, *ctrls[2], **ctrlsp = NULL;
   352→	BerElement *ber = NULL;
   353→
   354→	if ( verbose ) printf ( _("deleting children of: %s\n"), base );
   355→
   356→	if ( subentries ) {
   357→		/*
   358→		 * Do a one level search at base for subentry children.
   359→		 */
   360→
   361→		if ((ber = ber_alloc_t(LBER_USE_DER)) == NULL) {
   362→			return EXIT_FAILURE;
   363→		}
   364→		rc = ber_printf( ber, "b", 1 );
   365→		if ( rc == -1 ) {
   366→			ber_free( ber, 1 );
   367→			fprintf( stderr, _("Subentries control encoding error!\n"));
   368→			return EXIT_FAILURE;
   369→		}
   370→		if ( ber_flatten2( ber, &c.ldctl_value, 0 ) == -1 ) {
   371→			return EXIT_FAILURE;
   372→		}
   373→		c.ldctl_oid = LDAP_CONTROL_SUBENTRIES;
   374→		c.ldctl_iscritical = 1;
   375→		ctrls[0] = &c;
   376→		ctrls[1] = NULL;
   377→		ctrlsp = ctrls;
   378→	}
   379→
   380→	/*
   381→	 * Do a one level search at base for children.  For each, delete its children.
   382→	 */
   383→more:;
   384→	srch_rc = ldap_search_ext_s( ld, base, LDAP_SCOPE_ONELEVEL, NULL, attrs, 1,
   385→		ctrlsp, NULL, NULL, sizelimit, &res );
   386→	switch ( srch_rc ) {
   387→	case LDAP_SUCCESS:
   388→	case LDAP_SIZELIMIT_EXCEEDED:
   389→		break;
   390→	default:
   391→		tool_perror( "ldap_search", srch_rc, NULL, NULL, NULL, NULL );
   392→		return( srch_rc );
   393→	}
   394→
   395→	entries = ldap_count_entries( ld, res );
   396→
   397→	if ( entries > 0 ) {
   398→		int i;
   399→
   400→		for (e = ldap_first_entry( ld, res ), i = 0; e != NULL;
   401→			e = ldap_next_entry( ld, e ), i++ )
   402→		{
   403→			char *dn = ldap_get_dn( ld, e );
   404→
   405→			if( dn == NULL ) {
   406→				ldap_get_option( ld, LDAP_OPT_RESULT_CODE, &rc );
   407→				tool_perror( "ldap_prune", rc, NULL, NULL, NULL, NULL );
   408→				ber_memfree( dn );
   409→				return rc;
   410→			}
   411→
   412→			rc = deletechildren( ld, dn, 0 );
   413→			if ( rc != LDAP_SUCCESS ) {
   414→				tool_perror( "ldap_prune", rc, NULL, NULL, NULL, NULL );
   415→				ber_memfree( dn );
   416→				return rc;
   417→			}
   418→
   419→			if ( verbose ) {
   420→				printf( _("\tremoving %s\n"), dn );
   421→			}
   422→
   423→			rc = ldap_delete_ext_s( ld, dn, NULL, NULL );
   424→			if ( rc != LDAP_SUCCESS ) {
   425→				tool_perror( "ldap_delete", rc, NULL, NULL, NULL, NULL );
   426→				ber_memfree( dn );
   427→				return rc;
   428→
   429→			}
   430→			
   431→			if ( verbose ) {
   432→				printf( _("\t%s removed\n"), dn );
   433→			}
   434→
   435→			ber_memfree( dn );
   436→		}
   437→	}
   438→
   439→	ldap_msgfree( res );
   440→
   441→	if ( srch_rc == LDAP_SIZELIMIT_EXCEEDED ) {
   442→		goto more;
   443→	}
   444→
   445→	return rc;
   446→}
   447→

